css:
.loader {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 80px;
  aspect-ratio: 2;
  box-sizing: content-box;
  border-bottom: 8px solid #0000;
  background:linear-gradient(90deg,var(--loader-secondary-color, #5eead4) 50%,var(--loader-color, #0f766e) 0)50% 100%/52% 8px border-box repeat-x;
  animation: l8-0 1s linear infinite;
}.loader:before {content:"";
  margin: 0 25%;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #0f766e) 0 60deg,var(--loader-secondary-color, #5eead4) 0 120deg);
  animation: l8-1 1s linear infinite;
}@keyframes l8-0 {to{background-position: -58% 100%}}@keyframes l8-1 {to{rotate: 120deg}}
